### Swift Associated Types

Associated types give a placeholder name to a type used in a protocol. The actual type is specified when the protocol is adopted, making protocols generic without exposing concrete types.

**Associated Type Syntax:**

```swift
protocol Container {
    associatedtype Item
    var count: Int { get }
    mutating func append(_ item: Item)
    subscript(index: Int) -> Item { get }
}

struct IntStack: Container {
    // Swift infers Item == Int
    private var items: [Int] = []

    var count: Int { items.count }

    mutating func append(_ item: Int) {
        items.append(item)
    }

    subscript(index: Int) -> Int {
        items[index]
    }
}

struct StringStack: Container {
    typealias Item = String  // Explicit
    private var items: [String] = []

    var count: Int { items.count }

    mutating func append(_ item: String) {
        items.append(item)
    }

    subscript(index: Int) -> String {
        items[index]
    }
}
```

**Using Associated Types in Constraints:**

```swift
protocol Container {
    associatedtype Item
    mutating func append(_ item: Item)
    var count: Int { get }
    subscript(i: Int) -> Item { get }
}

// Constrain associated type
protocol SortableContainer: Container where Item: Comparable {
    func sorted() -> [Item]
}

// Generic function with associated type constraint
func allItemsMatch<C1: Container, C2: Container>(_ a: C1, _ b: C2) -> Bool
    where C1.Item == C2.Item, C1.Item: Equatable {
    guard a.count == b.count else { return false }
    for i in 0..<a.count {
        guard a[i] == b[i] else { return false }
    }
    return true
}
```

**Associated Type with Protocol Inheritance:**

```swift
protocol IteratorProtocol {
    associatedtype Element
    mutating func next() -> Element?
}

protocol Sequence {
    associatedtype Iterator: IteratorProtocol
    associatedtype Element where Element == Iterator.Element

    func makeIterator() -> Iterator
}
```

**Adding Constraints:**

```swift
protocol Container {
    associatedtype Item
    associatedtype Index: Comparable where Index: Hashable

    var startIndex: Index { get }
    var endIndex: Index { get }
    subscript(position: Index) -> Item { get }
}
```

> **Key Point:** Associated types make protocols generic. They are resolved when a type conforms to the protocol, either through explicit `typealias` or type inference.

Use `typealias` to make associated types explicit, or let Swift infer them from the implementation.

codeExample:
import Foundation

// Protocol with associated type
protocol StackProtocol {
    associatedtype Element
    mutating func push(_ element: Element)
    mutating func pop() -> Element?
    var isEmpty: Bool { get }
}

struct Stack<T>: StackProtocol {
    typealias Element = T
    private var items: [T] = []

    mutating func push(_ element: T) {
        items.append(element)
    }

    mutating func pop() -> T? {
        items.popLast()
    }

    var isEmpty: Bool { items.isEmpty }
}

// Generic function using protocol with associated type
func processStack<S: StackProtocol>(_ stack: inout S) where S.Element: CustomStringConvertible {
    while !stack.isEmpty {
        if let item = stack.pop() {
            print("Popped: \(item.description)")
        }
    }
}

var intStack = Stack<Int>()
intStack.push(10)
intStack.push(20)
intStack.push(30)

var stringStack = Stack<String>()
stringStack.push("Hello")
stringStack.push("World")

processStack(&intStack)
processStack(&stringStack)
